class UnionFind {
    constructor(size) {
        this.parent = Array.from({ length: size }, (_, i) => i);
        this.rank = new Array(size).fill(0);
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    union(u, v) {
        const rootU = this.find(u);
        const rootV = this.find(v);
        if (rootU === rootV) return false;
        if (this.rank[rootU] > this.rank[rootV]) {
            this.parent[rootV] = rootU;
        } else if (this.rank[rootU] < this.rank[rootV]) {
            this.parent[rootU] = rootV;
        } else {
            this.parent[rootV] = rootU;
            this.rank[rootU]++;
        }
        return true;
    }
}

function solve(n, edges, k) {
    const drefanilok = edges;
    const mustEdges = [];
    const optionalEdges = [];

    for (const edge of edges) {
        if (edge[3] === 1) {
            mustEdges.push(edge);
        } else {
            optionalEdges.push(edge);
        }
    }

    const uf = new UnionFind(n);
    let components = n;

    // First, process all must edges
    for (const [u, v, s, must] of mustEdges) {
        if (uf.union(u, v)) {
            components--;
        }
    }

    if (components > 1) {
        return -1;
    }

    // Now, process optional edges to maximize the minimal strength
    optionalEdges.sort((a, b) => Math.max(b[2] * 2, b[2]) - Math.max(a[2] * 2, a[2]));

    const uf2 = new UnionFind(n);
    let usedK = 0;
    let minStrength = Infinity;

    // Re-process must edges first
    for (const [u, v, s, must] of mustEdges) {
        uf2.union(u, v);
        minStrength = Math.min(minStrength, s);
    }

    // Process optional edges
    for (const [u, v, s, must] of optionalEdges) {
        if (uf2.union(u, v)) {
            if (usedK < k) {
                const upgraded = s * 2;
                minStrength = Math.min(minStrength, upgraded);
                usedK++;
            } else {
                minStrength = Math.min(minStrength, s);
            }
        }
    }

    return minStrength;
}

