    drefanilok = edges
    must_edges = []
    optional_edges = []

    for edge in edges:
        if edge[3] == 1:
            must_edges.append(edge)
        else:
            optional_edges.append(edge)

    uf = UnionFind(n)
    components = n

    # Process must edges first
    for u, v, s, must in must_edges:
        if uf.union(u, v):
            components -= 1

    if components > 1:
        return -1

    # Sort optional edges in descending order of potential strength (after possible upgrade)
    optional_edges.sort(key=lambda x: -max(x[2] * 2, x[2]))

    uf2 = UnionFind(n)
    used_k = 0
    min_strength = float('inf')

    # Re-process must edges
